import { Component, Input, OnInit, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-skeleton',
  template: `<span class="skeleton" [style.width]="width" [style.height]="height" [style.border-radius]="radius"></span>`,
  styles: [`
    .skeleton { display: block; background: linear-gradient(90deg, #e5e7eb 25%, #f3f4f6 37%, #e5e7eb 63%); background-size: 400% 100%; animation: skeleton-shimmer 1.4s ease infinite; }
    @keyframes skeleton-shimmer { 0% { background-position: 100% 0; } 100% { background-position: 0 0; } }
  `],
})
export class SkeletonComponent {
  @Input() width = '100%';
  @Input() height = '16px';
  @Input() radius = '4px';
}

@Component({
  selector: 'app-skeleton-card',
  template: `
    <div *ngIf="loading; else loaded" class="card" aria-hidden="true">
      <app-skeleton width="48px" height="48px" radius="50%"></app-skeleton>
      <div class="lines">
        <app-skeleton width="60%" height="14px"></app-skeleton>
        <app-skeleton width="90%" height="12px"></app-skeleton>
        <app-skeleton width="40%" height="12px"></app-skeleton>
      </div>
    </div>
    <ng-template #loaded>
      <div class="card">
        <div class="avatar">AL</div>
        <div>
          <div class="name">Ada Lovelace</div>
          <div class="bio">First computer programmer.</div>
          <div class="handle">@ada</div>
        </div>
      </div>
    </ng-template>
  `,
  styles: [`
    .card { display: flex; gap: 14px; align-items: center; width: 320px; padding: 16px; border: 1px solid #eee; border-radius: 12px; }
    .lines { flex: 1; display: flex; flex-direction: column; gap: 8px; }
    .avatar { width: 48px; height: 48px; border-radius: 50%; background: #2563eb; color: #fff; display: flex; align-items: center; justify-content: center; font-weight: 700; }
    .name { font-weight: 700; }
    .bio { color: #555; font-size: 14px; }
    .handle { color: #999; font-size: 12px; }
  `],
})
export class SkeletonCardComponent implements OnInit, OnDestroy {
  loading = true;
  private timer: any = null;

  ngOnInit(): void {
    this.reload();
  }

  reload(): void {
    this.loading = true;
    clearTimeout(this.timer);
    this.timer = setTimeout(() => {
      this.loading = false;
    }, 2000);
  }

  ngOnDestroy(): void {
    clearTimeout(this.timer);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Skeleton Loader Demo</h1>
      <button (click)="card.reload()" style="margin-bottom: 16px; padding: 6px 12px; cursor: pointer;">Reload</button>
      <app-skeleton-card #card></app-skeleton-card>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, SkeletonComponent, SkeletonCardComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
